from collections import Counter

def ngrams(tokens: list[str], n: int) -> Counter:
    return Counter(tuple(tokens[i:i+n]) for i in range(len(tokens) - n + 1))

def rouge_n(prediction: str, reference: str, n: int) -> dict:
    """
    Compute ROUGE-N recall, precision, and F1.
    Standard ROUGE emphasises recall (how much of the reference is captured).
    """
    pred_tokens = tokenise(prediction)
    ref_tokens  = tokenise(reference)

    pred_ng = ngrams(pred_tokens, n)
    ref_ng  = ngrams(ref_tokens, n)

    common = sum((pred_ng & ref_ng).values())
    if not ref_ng:
        return {"recall": 0.0, "precision": 0.0, "f1": 0.0}

    recall    = common / sum(ref_ng.values())
    precision = common / sum(pred_ng.values()) if pred_ng else 0.0
    f1 = 2 * precision * recall / (precision + recall) if (precision + recall) > 0 else 0.0

    return {"recall": recall, "precision": precision, "f1": f1}

def rouge_scores(prediction: str, reference: str) -> dict:
    return {
        "rouge1": rouge_n(prediction, reference, 1),
        "rouge2": rouge_n(prediction, reference, 2),
    }

# Quick eval across a dataset
def mean_rouge(predictions: list[str], references: list[str]) -> dict:
    from statistics import mean
    all_scores = [rouge_scores(p, r) for p, r in zip(predictions, references)]
    return {
        "rouge1_f1": mean(s["rouge1"]["f1"] for s in all_scores),
        "rouge2_f1": mean(s["rouge2"]["f1"] for s in all_scores),
    }

from anthropic import Anthropic

client = Anthropic()

REFERENCE_JUDGE_PROMPT = """You are evaluating an agent response against a reference answer.

User question: {user_input}
Reference answer: {reference}
Agent response: {prediction}

Score the agent response on how well it captures the key information in the reference answer.
- 1.0: Captures all key points, no factual contradictions
- 0.7: Captures most key points, minor gaps
- 0.5: Captures about half the key points
- 0.3: Misses most key points or contains errors
- 0.0: Contradicts the reference or is entirely off-topic

Return only a float."""

def reference_guided_judge(
    user_input: str,
    reference: str,
    prediction: str,
    model: str = "claude-haiku-4-5-20251001",
) -> float:
    prompt = REFERENCE_JUDGE_PROMPT.format(
        user_input=user_input,
        reference=reference,
        prediction=prediction,
    )
    msg = client.messages.create(
        model=model,
        max_tokens=8,
        messages=[{"role": "user", "content": prompt}],
    )
    try:
        return float(msg.content[0].text.strip())
    except ValueError:
        return 0.0

def score_against_best_reference(
    prediction: str,
    references: list[str],
    score_fn,
) -> float:
    """Return the maximum score achieved against any reference."""
    return max(score_fn(prediction, ref) for ref in references)

def multi_ref_token_f1(prediction: str, references: list[str]) -> float:
    return score_against_best_reference(prediction, references, token_f1)

def multi_ref_rouge1(prediction: str, references: list[str]) -> float:
    return score_against_best_reference(
        prediction, references,
        lambda p, r: rouge_n(p, r, 1)["f1"]
    )

from dataclasses import dataclass

EXACT_PASS = 1.0
F1_PASS_THRESHOLD = 0.85
SEM_PASS_THRESHOLD = 0.80

@dataclass
class TieredEvalResult:
    method_used: str
    score: float
    passed: bool

def tiered_reference_eval(
    prediction: str,
    references: list[str],
    user_input: str,
    embed_fn=None,
    use_judge: bool = True,
) -> TieredEvalResult:
    """
    Evaluate prediction against references using the cheapest method
    that yields a decisive result.
    """
    # Tier 1: exact match
    for ref in references:
        if prediction.strip() == ref.strip():
            return TieredEvalResult("exact_match", EXACT_PASS, True)

    # Tier 2: token F1
    f1 = multi_ref_token_f1(prediction, references)
    if f1 >= F1_PASS_THRESHOLD:
        return TieredEvalResult("token_f1", f1, True)
    if f1 < 0.30:  # clearly wrong — skip remaining tiers
        return TieredEvalResult("token_f1", f1, False)

    # Tier 3: semantic similarity (if embed_fn provided)
    if embed_fn is not None:
        sim = max(
            semantic_similarity(prediction, ref, embed_fn)
            for ref in references
        )
        if sim >= SEM_PASS_THRESHOLD:
            return TieredEvalResult("semantic_sim", sim, True)
        if sim < 0.50:
            return TieredEvalResult("semantic_sim", sim, False)

    # Tier 4: reference-guided LLM judge
    if use_judge:
        best_ref = max(references, key=lambda r: token_f1(prediction, r))
        judge_score = reference_guided_judge(user_input, best_ref, prediction)
        return TieredEvalResult("llm_judge", judge_score, judge_score >= 0.70)

    return TieredEvalResult("token_f1", f1, False)

from datetime import datetime

@dataclass
class VersionedReference:
    text: str
    prompt_version: str
    valid_from: str
    valid_until: str | None = None   # None = currently valid

    def is_current(self, as_of: str | None = None) -> bool:
        now = as_of or datetime.utcnow().isoformat()
        if self.valid_until and now > self.valid_until:
            return False
        return now >= self.valid_from

def active_references(
    versioned_refs: list[VersionedReference],
) -> list[str]:
    """Return reference texts that are currently valid."""
    return [r.text for r in versioned_refs if r.is_current()]
